import{_ as r,o as t,c as s,j as a,a as n,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const m=JSON.parse('{"title":"吐花症","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/杂项/吐花症.md","filePath":"4.资源分区/6.技艺及称号/杂项/吐花症.md"}'),d={name:"4.资源分区/6.技艺及称号/杂项/吐花症.md"};function p(l,e,_,i,c,b){return t(),s("div",null,[...e[0]||(e[0]=[a("h1",{id:"吐花症",tabindex:"-1"},[n("吐花症 "),a("a",{class:"header-anchor",href:"#吐花症","aria-label":'Permalink to "吐花症"'},"​")],-1),a("table",{class:"bannerparthead"},[a("tbody",null,[a("tr",{id:"hdr"},[a("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调018")])])],-1),o('<h1 id="吐花症-1" tabindex="-1">吐花症 <a class="header-anchor" href="#吐花症-1" aria-label="Permalink to &quot;吐花症&quot;">​</a></h1><p>吐花症<br> D+500<br> 我是一个卖花女……我患了一种病，我不知道这是福是祸，但我规避了那些奇怪的花，我会找到那朵山茶花吧？<br> 【心壤】:每天一次，你在接触的异性（可指定目标）的时候，你心中会生长1朵属于他/她【孕花】，无论如何这次接触将不再生长【孕花】，同样的，如果第二天你选择了别的异性，那么原本属于他/她的那朵【孕花】则直接枯萎消失。</p><p>【孕花】<br> 它会在你不进行社交的时候消失。<br> 每有1朵【孕花】你面对属于该【孕花】的人物时，增加相当于你自身风度附加成功*2点社交检定的增强加值，如果不是，社交时则减少相当于你自身风度附加成功*2点社交检定表现减值。</p><p>【花开】:在【孕花】达到3朵的时候，你将不可控制的吐出全部数量，和对方品质或对方对你的态度（可和st要求）相关花语或者特点的花，同时清空【孕花】。<br> 如果不想特别去找，那么请参考以下花语。<br> 玫瑰（多情/爱/热烈的感情）<br> 鸢尾花（微毒/友谊永固）<br> 蝴蝶兰（伪装/友情开始）<br> 山茶花（纯洁/理想的爱）<br> 在吐出花后，若对方将其吃下去，则会因此获得1点情绪异常治疗点数（24医疗点），这个能力将持续一场景。若没有选择在此场景中吃下花，则这些花会立即枯萎，无法再食用。</p><p>选开:<br> 【花腐】：每进入一个影片，你选择一个心仪的对象进行绑定，你的【孕花】目标必定是他/她，在影片结束时，你必须将吐出的花朵让对方心甘情愿的吃掉，否则你将永远失去吐花症。但因此获得的吐花症的医疗点变为48点，且那点情绪异常治疗点数可以永久保留，但每名角色只能因此而吃下【孕花】一次。</p><hr><p>Copyright ? 2024 TMDtrpg制作组. All Rights Reserved.</p>',7)])])}const f=r(d,[["render",p]]);export{m as __pageData,f as default};
